/* global document, Excel, Office */

const SECRET = "DC2026SECRET";
const DAY_NAMES = ["日", "月", "火", "水", "木", "金", "土"];

const DEFAULT_CONFIG = {
  calcMethod: "曜日",
  order: { sheetName: "受注一覧", customerCodeCol: 1, productCodeCol: 6, makerCodeCol: 9, logisticsCol: 10, arrivalCol: 11, deliveryCol: 12, warehouseCol: 13 },
  sheetNames: { maker: "TBL_MAKER", customer: "TBL_CUSTOMER", warehouse: "TBL_WAREHOUSE", holiday: "TBL_HOLIDAY", itemIrr: "TBL_ITEM_IRREGULAR", makerIrr: "TBL_MAKER_IRREGULAR" }
};

let cfg = JSON.parse(JSON.stringify(DEFAULT_CONFIG));

async function sha256(message) {
  const msgBuffer = new TextEncoder().encode(message);
  const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);
  return Array.from(new Uint8Array(hashBuffer)).map(b => b.toString(16).padStart(2, "0")).join("");
}

async function generateKey(email) {
  const raw = await sha256(email.toLowerCase() + SECRET);
  const chars = raw.toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 12);
  return "DC-" + chars.slice(0, 4) + "-" + chars.slice(4, 8) + "-" + chars.slice(8, 12);
}

async function validateLicense(email, key) {
  return key.toUpperCase() === await generateKey(email);
}

async function activateLicense() {
  const msg = document.getElementById("msg-license");
  const email = document.getElementById("license-email").value.trim();
  const key = document.getElementById("license-key").value.trim();
  if (!email || !key) { msg.textContent = "❌ メールアドレスとライセンスキーを入力してください"; return; }
  msg.textContent = "認証中...";
  try {
    if (await validateLicense(email, key)) {
      await saveLicense(email, key);
      const license = await loadLicense();
      showApp(license);
    } else {
      msg.textContent = "❌ ライセンスキーが無効です";
    }
  } catch(e) {
    msg.textContent = "❌ エラー: " + e.message;
  }
}

Office.onReady(async (info) => {
  if (info.host === Office.HostType.Excel) {
    try {
      document.getElementById("sideload-msg").style.display = "none";
      document.getElementById("btn-activate").onclick = activateLicense;
      document.getElementById("btn-logout").onclick = logoutLicense;
      document.getElementById("btn-init-master").onclick = initMaster;
      document.getElementById("btn-calc-delivery").onclick = calcDelivery;
      document.getElementById("btn-save-settings").onclick = saveSettings;
      document.getElementById("btn-reset-settings").onclick = resetSettings;
      document.getElementById("btn-toggle-settings").onclick = toggleSettings;
      document.getElementById("btn-method-weekday").onclick = function() { cfg.calcMethod = "曜日"; updateCalcMethodUI(); };
      document.getElementById("btn-method-days").onclick = function() { cfg.calcMethod = "日数"; updateCalcMethodUI(); };
      await loadConfig();
      updateCalcMethodUI();
      const license = await loadLicense();
      if (license && await validateLicense(license.email, license.key)) {
        showApp(license);
      } else {
        showLicenseScreen();
      }
    } catch(e) {
      document.getElementById("sideload-msg").style.display = "block";
      document.getElementById("sideload-msg").textContent = "エラー：" + e.message;
    }
  }
});

function showLicenseScreen() {
  document.getElementById("license-screen").style.display = "block";
  document.getElementById("app-body").style.display = "none";
}

function showApp(license) {
  document.getElementById("license-screen").style.display = "none";
  document.getElementById("app-body").style.display = "block";
  document.getElementById("license-info").innerHTML = "✅ 認証済み：" + license.email + "<br>有効期限：" + license.expiry;
}

async function saveLicense(email, key) {
  await Excel.run(async (context) => {
    const props = context.workbook.properties.custom;
    try { props.getItemOrNullObject("DC_EMAIL").delete(); } catch(e) {}
    try { props.getItemOrNullObject("DC_KEY").delete(); } catch(e) {}
    await context.sync();
    props.add("DC_EMAIL", email);
    props.add("DC_KEY", key);
    await context.sync();
  });
}

async function loadLicense() {
  try {
    const email = localStorage.getItem("DC_EMAIL");
    const key = localStorage.getItem("DC_KEY");
    if (!email || !key) return null;
    return { email, key, expiry: "無期限" };
  } catch (e) { return null; }
}

async function logoutLicense() {
  await Excel.run(async (context) => {
    const props = context.workbook.properties.custom;
    props.getItemOrNullObject("DC_EMAIL").delete();
    props.getItemOrNullObject("DC_KEY").delete();
    await context.sync();
  });
  showLicenseScreen();
}

async function saveConfig() {
  try {
    await Excel.run(async (context) => {
      const xml = `<?xml version="1.0"?><DC_CONFIG>${JSON.stringify(cfg)}</DC_CONFIG>`;
      const parts = context.workbook.customXmlParts;
      const existing = parts.getByNamespace("DC_CONFIG");
      existing.load("items");
      await context.sync();
      existing.items.forEach(p => p.delete());
      parts.add(xml);
      await context.sync();
    });
  } catch (e) { console.error("設定保存エラー", e); }
}

async function loadConfig() {
  try {
    await Excel.run(async (context) => {
      const parts = context.workbook.customXmlParts;
      const existing = parts.getByNamespace("DC_CONFIG");
      existing.load("items");
      await context.sync();
      if (existing.items.length > 0) {
        const xmlString = existing.items[0].getXml();
        await context.sync();
        const text = xmlString.value.replace(/<\/?DC_CONFIG[^>]*>/g, "");
        const saved = JSON.parse(text);
        cfg.calcMethod = saved.calcMethod || DEFAULT_CONFIG.calcMethod;
        cfg.order = Object.assign(JSON.parse(JSON.stringify(DEFAULT_CONFIG.order)), saved.order || {});
        cfg.sheetNames = Object.assign(JSON.parse(JSON.stringify(DEFAULT_CONFIG.sheetNames)), saved.sheetNames || {});
      }
    });
  } catch (e) { cfg = JSON.parse(JSON.stringify(DEFAULT_CONFIG)); }
}

function updateCalcMethodUI() {
  const isWeekday = cfg.calcMethod === "曜日";
  document.getElementById("btn-method-weekday").className = isWeekday ? "method-btn method-active" : "method-btn";
  document.getElementById("btn-method-days").className = isWeekday ? "method-btn" : "method-btn method-active";
  document.getElementById("method-label").textContent = "演算方法：" + cfg.calcMethod + "モード";
}

async function setCalcMethod(method) {
  cfg.calcMethod = method;
  updateCalcMethodUI();
  await saveConfig();
}

function toggleSettings() {
  const panel = document.getElementById("settings-panel");
  const btn = document.getElementById("btn-toggle-settings");
  const isHidden = panel.style.display === "none" || panel.style.display === "";
  panel.style.display = isHidden ? "block" : "none";
  btn.textContent = isHidden ? "▲ 設定を閉じる" : "⚙️ 列・シート設定を開く";
  if (isHidden) populateSettings();
}

function populateSettings() {
  const o = cfg.order, s = cfg.sheetNames;
  const fields = {
    "s-order-sheet": o.sheetName, "s-order-customer-col": o.customerCodeCol,
    "s-order-product-col": o.productCodeCol, "s-order-maker-col": o.makerCodeCol,
    "s-order-logistics-col": o.logisticsCol, "s-order-warehouse-col": o.warehouseCol, "s-order-arrival-col": o.arrivalCol,
    "s-order-delivery-col": o.deliveryCol, "s-maker-sheet": s.maker,
    "s-customer-sheet": s.customer, "s-warehouse-sheet": s.warehouse,
    "s-holiday-sheet": s.holiday, "s-item-irr-sheet": s.itemIrr, "s-maker-irr-sheet": s.makerIrr
  };
  for (const [id, val] of Object.entries(fields)) { const el = document.getElementById(id); if (el) el.value = val; }
}

async function saveSettings() {
  cfg.order.sheetName = document.getElementById("s-order-sheet").value.trim();
  cfg.order.customerCodeCol = parseInt(document.getElementById("s-order-customer-col").value);
  cfg.order.productCodeCol = parseInt(document.getElementById("s-order-product-col").value);
  cfg.order.makerCodeCol = parseInt(document.getElementById("s-order-maker-col").value);
  cfg.order.logisticsCol = parseInt(document.getElementById("s-order-logistics-col").value);
  cfg.order.warehouseCol = parseInt(document.getElementById("s-order-warehouse-col").value);
  cfg.order.arrivalCol = parseInt(document.getElementById("s-order-arrival-col").value);
  cfg.order.deliveryCol = parseInt(document.getElementById("s-order-delivery-col").value);
  cfg.sheetNames.maker = document.getElementById("s-maker-sheet").value.trim();
  cfg.sheetNames.customer = document.getElementById("s-customer-sheet").value.trim();
  cfg.sheetNames.warehouse = document.getElementById("s-warehouse-sheet").value.trim();
  cfg.sheetNames.holiday = document.getElementById("s-holiday-sheet").value.trim();
  cfg.sheetNames.itemIrr = document.getElementById("s-item-irr-sheet").value.trim();
  cfg.sheetNames.makerIrr = document.getElementById("s-maker-irr-sheet").value.trim();
  await saveConfig();
  showMsg("msg-settings", "✅ 設定を保存しました");
}

async function resetSettings() {
  cfg = JSON.parse(JSON.stringify(DEFAULT_CONFIG));
  await saveConfig();
  populateSettings();
  updateCalcMethodUI();
  showMsg("msg-settings", "✅ デフォルトに戻しました");
}

function showMsg(id, text, ms = 3000) {
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = text;
  setTimeout(() => { el.textContent = ""; }, ms);
}

async function initMaster() {
  const msg = document.getElementById("msg-init");
  msg.textContent = "作成中...";
  try {
    await Excel.run(async (context) => {
      const sheets = context.workbook.worksheets;
      const isWeekday = cfg.calcMethod === "曜日";
      const sn = cfg.sheetNames;
      const irrHeaders = isWeekday ? ["得意先コード","得意先名","コード","名称","月","火","水","木","金","土","日"] : ["得意先コード","得意先名","コード","名称","日数（営業日）"];
      const masterDefs = [
        { name: sn.maker, headers: isWeekday ? ["発注先コード","メーカー名称","受注締め時間","月→納品","火→納品","水→納品","木→納品","金→納品","旗日明け加算"] : ["発注先コード","メーカー名称","受注締め時間","リードタイム（営業日）","旗日明け加算"], data: [] },
        { name: sn.customer, headers: ["得意先コード","得意先名称","月","火","水","木","金","土","日"], data: [] },
        { name: sn.warehouse, headers: ["倉庫コード","倉庫名","区分","月","火","水","木","金","土","日","祝日","締め時間"], data: [["WH001","本社倉庫","入荷","〇","〇","〇","〇","〇","〇","×","×","14:00"],["WH001","本社倉庫","納品","〇","〇","〇","〇","〇","×","×","×",""],["WH002","第二倉庫","入荷","〇","〇","〇","〇","〇","〇","×","×","15:00"],["WH002","第二倉庫","納品","〇","〇","〇","〇","〇","×","×","×",""] ] },
        { name: sn.holiday, headers: ["日付","祝日名"], data: [] },
        { name: sn.itemIrr, headers: irrHeaders, data: [] },
        { name: sn.makerIrr, headers: irrHeaders, data: [] }
      ];
      for (const master of masterDefs) {
        const existing = sheets.getItemOrNullObject(master.name);
        await context.sync();
        if (!existing.isNullObject) existing.delete();
        const sheet = sheets.add(master.name);
        const headerRange = sheet.getRangeByIndexes(0, 0, 1, master.headers.length);
        headerRange.values = [master.headers];
        headerRange.format.fill.color = "#217346";
        headerRange.format.font.color = "white";
        headerRange.format.font.bold = true;
        headerRange.format.columnWidth = 120;
        if (master.data.length > 0) sheet.getRangeByIndexes(1, 0, master.data.length, master.headers.length).values = master.data;
      }
      await context.sync();
      msg.textContent = "✅ マスタシートを作成しました！";
    });
  } catch (e) { msg.textContent = "❌ エラー：" + e.message; }
}

function excelDateToDate(serial) { return new Date(Math.floor(serial - 25569) * 86400 * 1000); }
function formatDate(date) { return date.getUTCFullYear() + "/" + String(date.getUTCMonth() + 1).padStart(2, "0") + "/" + String(date.getUTCDate()).padStart(2, "0"); }
async function loadHolidays(context) { const sheet = context.workbook.worksheets.getItem(cfg.sheetNames.holiday); const range = sheet.getUsedRange(); range.load("values"); await context.sync(); return range.values.slice(1).filter(r => r[0]).map(r => formatDate(excelDateToDate(r[0]))); }
async function loadMakers(context) { const sheet = context.workbook.worksheets.getItem(cfg.sheetNames.maker); const range = sheet.getUsedRange(); range.load("values"); await context.sync(); const isWeekday = cfg.calcMethod === "曜日"; return range.values.slice(1).filter(r => r[0]).map(r => { const maker = { code: String(r[0]), name: r[1], deadline: r[2], holidayAdd: isWeekday ? (Number(r[8]) || 0) : (Number(r[4]) || 0) }; if (isWeekday) maker.deliveryMap = { "月": r[3], "火": r[4], "水": r[5], "木": r[6], "金": r[7] }; else maker.days = Number(r[3]) || 1; return maker; }); }
async function loadCustomers(context) { const sheet = context.workbook.worksheets.getItem(cfg.sheetNames.customer); const range = sheet.getUsedRange(); range.load("values"); await context.sync(); return range.values.slice(1).filter(r => r[0]).map(r => ({ code: String(r[0]), name: r[1], deliverable: { "月": r[2]==="〇", "火": r[3]==="〇", "水": r[4]==="〇", "木": r[5]==="〇", "金": r[6]==="〇", "土": r[7]==="〇", "日": r[8]==="〇" } })); }
async function loadWarehouse(context) { const sheet = context.workbook.worksheets.getItem(cfg.sheetNames.warehouse); const range = sheet.getUsedRange(); range.load("values"); await context.sync(); const wh = {}; let defaultCode = null; range.values.slice(1).forEach(r => { const code = String(r[0]||"").trim(); const kubun = String(r[2]||"").trim(); if (!code || !kubun) return; if (!defaultCode) defaultCode = code; if (!wh[code]) wh[code] = { name: r[1], 入荷: {}, 納品: {} }; wh[code][kubun] = { "月": r[3]==="〇", "火": r[4]==="〇", "水": r[5]==="〇", "木": r[6]==="〇", "金": r[7]==="〇", "土": r[8]==="〇", "日": r[9]==="〇", "祝日": r[10]==="〇", "締め時間": String(r[11]||"").trim() }; }); wh.__default = defaultCode; return wh; }
async function loadIrregulars(context, sheetName, keyField) { try { const sheet = context.workbook.worksheets.getItemOrNullObject(sheetName); await context.sync(); if (sheet.isNullObject) return []; const range = sheet.getUsedRange(); range.load("values"); await context.sync(); const isWeekday = cfg.calcMethod === "曜日"; return range.values.slice(1).filter(r => r[0] && r[2]).map(r => { const entry = { customerCode: String(r[0]), [keyField]: String(r[2]) }; if (isWeekday) { entry.deliveryMap = {}; const orderDay = String(r[4] || "").trim(); const deliveryDay = String(r[5] || "").trim(); if (orderDay && deliveryDay) entry.deliveryMap[orderDay] = deliveryDay; } else entry.days = Number(r[4]) || 1; return entry; }); } catch (e) { return []; } }
async function calcDelivery() { const msg = document.getElementById("msg-delivery"); const resultBox = document.getElementById("result-box"); const resultDetail = document.getElementById("result-detail"); resultBox.style.display = "none"; msg.innerHTML = "計算中..."; const now = new Date(); const o = cfg.order; try { await Excel.run(async (context) => { const holidays = await loadHolidays(context); const makers = await loadMakers(context); const customers = await loadCustomers(context); const warehouse = await loadWarehouse(context); const itemIrrs = await loadIrregulars(context, cfg.sheetNames.itemIrr, "productCode"); const makerIrrs = await loadIrregulars(context, cfg.sheetNames.makerIrr, "makerCode"); const orderSheet = context.workbook.worksheets.getItem(o.sheetName); const orderRange = orderSheet.getUsedRange(); orderRange.load("values"); await context.sync(); const rows = orderRange.values; let successCount = 0, errorCount = 0; const errorLog = []; for (let i = 1; i < rows.length; i++) { const row = rows[i]; const customerCode = String(row[o.customerCodeCol - 1] || "").trim(); if (!customerCode) continue; const productCode = String(row[o.productCodeCol - 1] || "").trim(); const makerCode = String(row[o.makerCodeCol - 1] || "").trim(); const logistics = String(row[o.logisticsCol - 1] || "").trim();
        const warehouseCode = o.warehouseCol ? String(row[o.warehouseCol - 1] || "").trim() : "";
        const whCode = (warehouseCode && warehouse[warehouseCode]) ? warehouseCode : warehouse.__default;
        const wh = warehouse[whCode] || {}; const customer = customers.find(c => c.code === customerCode); const maker = makers.find(m => m.code === makerCode); if (!customer) { errorLog.push((i+1)+"行目：得意先「"+customerCode+"」が見つかりません"); errorCount++; orderSheet.getRangeByIndexes(i,0,1,o.deliveryCol).format.fill.color="#FFCCCC"; continue; } if (logistics !== "在庫" && !maker) { errorLog.push((i+1)+"行目：発注先「"+makerCode+"」が見つかりません"); errorCount++; orderSheet.getRangeByIndexes(i,0,1,o.deliveryCol).format.fill.color="#FFCCCC"; continue; } try { const itemIrr = itemIrrs.find(e => e.customerCode === customerCode && e.productCode === productCode); const makerIrr = makerIrrs.find(e => e.customerCode === customerCode && e.makerCode === makerCode); const irr = itemIrr || makerIrr || null; let deliveryDate = null, arrivalDate = null; const isWeekdayMode = cfg.calcMethod === "曜日"; if (isWeekdayMode) { if (logistics === "在庫") deliveryDate = calcZaikoWeekday(now, customer, wh, holidays, irr); else if (logistics === "通過") { const r = calcTsuukaWeekday(now, maker, customer, wh, holidays, irr); deliveryDate = r.deliveryDate; arrivalDate = r.arrivalDate; } else if (logistics === "直送") deliveryDate = calcChokusoWeekday(now, maker, customer, holidays, irr); else throw new Error("物流形態「"+logistics+"」が不正です"); } else { if (logistics === "在庫") deliveryDate = calcZaikoDays(now, customer, wh, holidays, irr); else if (logistics === "通過") { const r = calcTsuukaDays(now, maker, customer, wh, holidays, irr); deliveryDate = r.deliveryDate; arrivalDate = r.arrivalDate; } else if (logistics === "直送") deliveryDate = calcChokusoDays(now, maker, customer, holidays, irr); else throw new Error("物流形態「"+logistics+"」が不正です"); } orderSheet.getRangeByIndexes(i,0,1,o.deliveryCol).format.fill.clear(); orderSheet.getRangeByIndexes(i,o.deliveryCol-1,1,1).values = [[formatDate(deliveryDate)]]; if (arrivalDate) orderSheet.getRangeByIndexes(i,o.arrivalCol-1,1,1).values = [[formatDate(arrivalDate)]]; successCount++; } catch (rowErr) { errorLog.push((i+1)+"行目："+rowErr.message); errorCount++; orderSheet.getRangeByIndexes(i,0,1,o.deliveryCol).format.fill.color="#FFCCCC"; } } await context.sync(); let html = "✅ "+successCount+"件完了"; if (errorCount > 0) html += "　❌ "+errorCount+"件エラー<br><br>"+errorLog.join("<br>"); resultDetail.innerHTML = html; resultBox.style.display = "block"; msg.innerHTML = ""; }); } catch (e) { msg.innerHTML = "❌ エラー：" + e.message; } }
function isBusinessDay(date, holidays) { const d = date.getUTCDay(); return d !== 0 && d !== 6 && !holidays.includes(formatDate(date)); }
